INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1000001, 190801, 0, 13, "様々なミニゲームをご用意してい\nますよ！\nどのミニゲームで遊びますか？", 1000, "2030-04-01 14:00:00", "2020-02-15 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1000002, 190801, 0, 13, "楽しいミニゲームをご紹介！\nあなたはどのミニゲームで\n遊びますか？", 1000, "2030-04-01 14:00:00", "2020-02-15 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1001001, 190801, 0, 13, "こちらは{0}ルピで\n販売中！\nぜひ購入して\n遊んでくださいね！", 1001, "2030-04-01 14:00:00", "2020-02-15 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1002001, 190801, 0, 12, "動くハートに合わせてタップ！\nシズルさんとエリコさんの\nチョコレートケーキ作りを\nお手伝いしましょう！", 1002, "2030-04-01 14:00:00", "2020-02-15 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1003001, 190801, 0, 11, "クウカさんを引っ張ってより遠く\nへ飛ばしてあげましょう！\n色々なハプニングでクウカさんに\nエクスタシーを届けましょう！", 1003, "2030-04-01 14:00:00", "2020-02-15 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1004001, 190801, 0, 3, "左右をタップしてマジムンを倒し\nましょう！\n放て！\n琉球犬アラウンドシュート！", 1004, "2030-04-01 14:00:00", "2020-02-15 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1005001, 190801, 0, 7, "パネルをタップしてドラゴンズ\nネストのみなさんと一緒に\nしりとり対決をしませんか？\nおしりに「ん」はご法度です。", 1005, "2030-04-01 14:00:00", "2020-02-15 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1006001, 190801, 0, 2, "素早い動きのネズミに合わせ、\nタップで撃退！\nやる気のリンさんと一緒に\n大切なチーズを守りましょう！", 1006, "2030-04-01 14:00:00", "2020-05-31 12:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1007001, 190801, 0, 4, "ミサトさんや部員のみなさんと\nバッティングの特訓ですよ！\nホームランを目指して、ボールを\nタイミングよく打ち返しましょう", 1007, "2030-04-01 14:00:00", "2020-08-15 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1008001, 190801, 0, 6, "カルミナメダルを使って、\n応援グッズをゲットしましょう！\nメダルはルピを使って\n交換できますよ。\n", 1008, "2030-04-01 14:00:00", "2021-08-31 12:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1009001, 190801, 0, 13, "食べたプリンはプリンノート\nで確認してみましょう！\nプリンの材料はルピを使って\n購入できますよ。", 1009, "2030-04-01 14:00:00", "2021-12-18 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1010001, 190801, 0, 4, "チームでクイズに挑みましょう！\nソロで自分の実力を試すか、マル\nチで仲間と一緒に遊ぶか、好きな\nモードを選んでくださいね♪", 1010, "2030-04-01 14:00:00", "2022-02-15 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1011001, 190801, 0, 6, "３つのラウンドを駆け抜け、\n総合１位を目指しましょう！\n参加者の皆さんの特徴や、\nＧＰの特徴にも注目です♪", 1011, "2030-04-01 14:00:00", "2022-07-18 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1012001, 190801, 0, 6, "キャルさん、スズナさんと一緒に\nクイズでお勉強しましょう！\n放課後の教室で二人きりって…\nなんだかドキドキしますね♪", 1012, "2030-04-01 14:00:00", "2023-09-18 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1013001, 190801, 0, 6, "魔物の討伐任務にいざ行軍！\nエリコさん、マコトさんの\n頼もしい背中は、\n新兵さんたちの憧れですね♪", 1013, "2030-04-01 14:00:00", "2024-04-18 15:00:00");
INSERT INTO `v1_d0e4c0a9d0b33f2f0f078b3cc3f5554f422a835456652e79cf17f4db89436931` VALUES (1014001, 190801, 0, 6, "バンディ・シスターズのみなさん\nと戦車バトルに挑戦です！\nパーツやメンバーの組み合わせで\nマシンの特徴が変化しますよ♪", 1014, "2030-04-01 14:00:00", "2024-11-18 15:00:00");
